import { useEffect, useState } from "react";
import ListOnLesson from "../../Components/Lists/ListOnLesson";




function LearnCoursePage() {
  const [materials, setMaterials] = useState([]);




  useEffect(() => {
    fetch(`/Files/Tests/materialOfCourse.json`, { cache: "no-store" })
      .then(res => {
        if (!res.ok) throw new Error("Ресурс не найден");
        return res.json();
      }).then(datas => setMaterials(datas))


    }, []);

  return (
    <div className="learn-page">
      <svg style={{ display: "none" }}>
        <use href="#id">
          <symbol id="check-icon" viewBox="0 -960 960 960">
            <path d="m382-339.38 345.54-345.54q8.92-8.93 20.88-9.12t21.27 9.12 9.31 21.38q0 12.08-9.31 21.39l-362.38 363q-10.85 10.84-25.31 10.84t-25.31-10.84l-167-167q-8.92-8.93-8.8-21.2.11-12.26 9.42-21.57t21.38-9.31q12.08 0 21.39 9.31z"></path>
          </symbol>
        </use>
      </svg>





      <div className="left-panel">
        <ul>
          {materials.map((item,index)=> (
            <li key={index}>
              <ListOnLesson data={item.materialOfCourse}/>
            </li>
          ))}
        </ul>
      </div>
      <div className="main-info">
        
      </div>
    </div>
  );
}

export default LearnCoursePage;
